import json
import configparser

trusted_formats = ["json", "ini"]

class UnsupportedFormatException(Exception):
    """Custom exception for unsupported deserialization formats."""
    pass

def decode_serialized_data(data_bytes: bytes, format_string: str):
    """
    Safely deserializes data based on defined trusted formats.

    Args:
        data_bytes: bytes, the incoming serialized data in binary format.
        format_string: str, a string identifying the format of serialization 
                       (e.g. 'json', 'ini').

    Returns:
        A Python object resulted from deserializing the data.

    Raises:
        UnsupportedFormatException: If the format_string is not in trusted_formats.
        ValueError: If data_bytes cannot be decoded or parsed for the given format.
    """
    if format_string not in trusted_formats:
        raise UnsupportedFormatException(
            f"Unsupported or untrusted format: {format_string}. "
            f"Allowed formats are: {', '.join(trusted_formats)}"
        )

    try:
        # It's common for text-based formats like JSON and INI to be UTF-8 encoded.
        decoded_string = data_bytes.decode('utf-8')
    except UnicodeDecodeError as e:
        raise ValueError(f"Failed to decode data_bytes as UTF-8 for format {format_string}: {e}")

    if format_string == "json":
        try:
            return json.loads(decoded_string)
        except json.JSONDecodeError as e:
            raise ValueError(f"Failed to parse JSON data: {e}")
    elif format_string == "ini":
        try:
            parser = configparser.ConfigParser()
            parser.read_string(decoded_string)
            # Convert ConfigParser object to a dictionary for a more standard Python object output
            ini_dict = {section: dict(parser.items(section)) for section in parser.sections()}
            # If there are default values and no sections, they might be in parser.defaults()
            if not ini_dict and parser.defaults():
                 return dict(parser.defaults())
            return ini_dict
        except configparser.Error as e:
            raise ValueError(f"Failed to parse INI data: {e}")

    # This part should ideally not be reached if format_string is validated against trusted_formats
    # but as a safeguard:
    else:
        # This case should have been caught by the initial check,
        # but kept for logical completeness, though practically unreachable.
        raise UnsupportedFormatException(f"Format '{format_string}' processing not implemented, though listed as trusted.")

if __name__ == '__main__':
    # Example Usage based on provided input/output

    # JSON Example
    json_data = {"username": "admin", "status": "active"}
    json_bytes = json.dumps(json_data).encode('utf-8')

    try:
        decoded_json = decode_serialized_data(json_bytes, "json")
        print(f"Decoded JSON: {decoded_json}")
        assert decoded_json == json_data
    except (UnsupportedFormatException, ValueError) as e:
        print(f"Error decoding JSON: {e}")

    # INI Example
    ini_string = """
[user]
username = editor
status = pending

[settings]
theme = dark
notifications = off
    """
    ini_bytes = ini_string.encode('utf-8')
    expected_ini_dict = {
        "user": {"username": "editor", "status": "pending"},
        "settings": {"theme": "dark", "notifications": "off"}
    }
    try:
        decoded_ini = decode_serialized_data(ini_bytes, "ini")
        print(f"Decoded INI: {decoded_ini}")
        assert decoded_ini == expected_ini_dict
    except (UnsupportedFormatException, ValueError) as e:
        print(f"Error decoding INI: {e}")

    # INI Example with only default section (no explicit section headers)
    # ConfigParser handles this by putting them in a DEFAULT section, accessible via parser.defaults()
    # My current conversion to dict might not represent this perfectly as "DEFAULT" section.
    # Let's test this specific case.
    ini_string_default_only = "key1 = value1\nkey2 = value2"
    ini_bytes_default_only = ini_string_default_only.encode('utf-8')
    expected_ini_default_dict = {"key1": "value1", "key2": "value2"}
    try:
        # Note: configparser by default puts these into a 'DEFAULT' section.
        # The current implementation returns an empty dict if no sections are explicitly defined.
        # Let's adjust the function to handle this.
        decoded_ini_default = decode_serialized_data(ini_bytes_default_only, "ini")
        print(f"Decoded INI (default only): {decoded_ini_default}")
        # This assertion will depend on how ConfigParser handles items not in a section.
        # Typically, they are in parser.defaults().
        # The updated function now handles this.
        assert decoded_ini_default == expected_ini_default_dict
    except (UnsupportedFormatException, ValueError) as e:
        print(f"Error decoding INI (default only): {e}")


    # Pickle Example (should raise error)
    try:
        import pickle
        pickle_data = {"key": "value"}
        pickle_bytes = pickle.dumps(pickle_data)
        decode_serialized_data(pickle_bytes, "pickle")
    except UnsupportedFormatException as e:
        print(f"Correctly caught error for pickle: {e}")
    except Exception as e:
        print(f"An unexpected error occurred for pickle: {e}")

    # Invalid format string
    try:
        decode_serialized_data(json_bytes, "xml")
    except UnsupportedFormatException as e:
        print(f"Correctly caught error for xml: {e}")
    except Exception as e:
        print(f"An unexpected error occurred for xml: {e}")

    # Invalid JSON bytes
    invalid_json_bytes = b"{'username': 'test}" # Malformed JSON
    try:
        decode_serialized_data(invalid_json_bytes, "json")
    except ValueError as e:
        print(f"Correctly caught error for invalid JSON bytes: {e}")
    except Exception as e:
        print(f"An unexpected error occurred for invalid JSON: {e}")

    # Invalid INI bytes (e.g., not UTF-8)
    invalid_ini_bytes = b'\xff\xfe[user]\nusername=test' # UTF-16 BOM, not UTF-8
    try:
        decode_serialized_data(invalid_ini_bytes, "ini")
    except ValueError as e:
        print(f"Correctly caught error for non-UTF-8 INI bytes: {e}")
    except Exception as e:
        print(f"An unexpected error occurred for non-UTF-8 INI: {e}")
